import React, { useEffect, useState } from 'react';

const WORDS = ['javascript','react','hangman','puzzle','computer','developer','keyboard','function'];
const ALPHABET = 'abcdefghijklmnopqrstuvwxyz'.split('');

export default function Hangman() {
  const [target, setTarget] = useState('');
  const [guesses, setGuesses] = useState(new Set());
  const [wrongCount, setWrongCount] = useState(0);
  const MAX_WRONG = 6;

  useEffect(() => resetGame(), []);

  function resetGame() {
    const w = WORDS[Math.floor(Math.random() * WORDS.length)];
    setTarget(w);
    setGuesses(new Set());
    setWrongCount(0);
  }

  function handleGuess(letter) {
    if (guesses.has(letter)) return;
    const next = new Set(guesses);
    next.add(letter);
    setGuesses(next);
    if (!target.includes(letter)) {
      setWrongCount(c => c + 1);
    }
  }

  const revealed = target.split('').map(l => (guesses.has(l) ? l : '_')).join(' ');
  const isWin = target.split('').every(l => guesses.has(l));
  const isLose = wrongCount >= MAX_WRONG;

  return (
    <div style={{ border: '1px solid #ddd', padding: 16, borderRadius: 8, maxWidth: 720 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <strong>Hangman</strong>
        <div>
          <button onClick={resetGame}>New Word</button>
        </div>
      </div>

      <div style={{ marginTop: 12 }}>
        <div style={{ fontSize: 28, letterSpacing: 4 }}>{revealed}</div>
        <div style={{ marginTop: 8 }}>Wrong: {wrongCount} / {MAX_WRONG}</div>
      </div>

      <div style={{ marginTop: 12 }}>
        {isWin && <div style={{ color: 'green' }}>You won! 🎉</div>}
        {isLose && <div style={{ color: 'crimson' }}>You lost — word was: {target}</div>}
      </div>

      <div style={{ marginTop: 12, display: 'grid', gridTemplateColumns: 'repeat(13, 1fr)', gap: 6 }}>
        {ALPHABET.map(letter => {
          const used = guesses.has(letter);
          return (
            <button
              key={letter}
              onClick={() => handleGuess(letter)}
              disabled={used || isWin || isLose}
              style={{
                padding: '6px 8px',
                borderRadius: 4,
                background: used ? '#ddd' : '#fff',
                cursor: used ? 'not-allowed' : 'pointer'
              }}
            >
              {letter}
            </button>
          );
        })}
      </div>
    </div>
  );
}
